package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.Field;

class GsonBuilderTest {

  @Test
  void testDisableHtmlEscaping() throws Exception {
    GsonBuilder gsonBuilder = new GsonBuilder();

    // Initially escapeHtmlChars should be true (DEFAULT_ESCAPE_HTML)
    Field escapeHtmlCharsField = GsonBuilder.class.getDeclaredField("escapeHtmlChars");
    escapeHtmlCharsField.setAccessible(true);
    boolean initialValue = escapeHtmlCharsField.getBoolean(gsonBuilder);
    assertTrue(initialValue, "escapeHtmlChars should be true by default");

    // Call disableHtmlEscaping and verify return value is the same instance
    GsonBuilder returned = gsonBuilder.disableHtmlEscaping();
    assertSame(gsonBuilder, returned, "disableHtmlEscaping should return this");

    // Verify escapeHtmlChars is now false
    boolean afterValue = escapeHtmlCharsField.getBoolean(gsonBuilder);
    assertFalse(afterValue, "escapeHtmlChars should be false after disableHtmlEscaping");
  }
}
